# TaskFlow Style (The Modern Way)
from airflow.decorators import dag, task
from datetime import datetime

@dag(dag_id='energy_meter_taskflow', schedule=None,
     start_date=datetime(2026, 1, 1), catchup=False)
def energy_meter_pipeline():

    @task()
    def extract(ds=None):
        return {'file_path': f'/data/meters/{ds}.csv', 'rows': 4_200_000}

    @task()
    def validate(extract_result: dict):
        print(f'Validating {extract_result["file_path"]}')
        return True

    @task()
    def notify(is_valid: bool):
        print(f'Pipeline status: {"SUCCESS" if is_valid else "FAILURE"}')

    extracted = extract()
    validated = validate(extracted)
    notify(validated)

energy_meter_pipeline()
